import{c as s,Q as n,j as l,m as i}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"音视频工程的未来","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/30-音视频工程的未来.md","filePath":"mediaTechLearning/30-音视频工程的未来.md","lastUpdated":1780887690000}'),e={name:"mediaTechLearning/30-音视频工程的未来.md"};function p(t,a,o,r,h,c){return n(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="音视频工程的未来" tabindex="-1">音视频工程的未来 <a class="header-anchor" href="#音视频工程的未来" aria-label="Permalink to &quot;音视频工程的未来&quot;">​</a></h1><p>音视频不会被一个新协议彻底替代。未来几年更像是多条链路并存:点播继续追压缩和成本,直播追低延迟和规模,会议追质量和 AI 能力。</p><blockquote><p>一句话先记住:<strong>未来的音视频工程不是单点技术升级,而是编码、传输、边缘、AI 处理和质量观测一起演进</strong>。</p></blockquote><hr><h2 id="一、编码继续变强-但兼容永远慢" tabindex="-1">一、编码继续变强,但兼容永远慢 <a class="header-anchor" href="#一、编码继续变强-但兼容永远慢" aria-label="Permalink to &quot;一、编码继续变强,但兼容永远慢&quot;">​</a></h2><p>AV1、下一代视频编码会继续提高压缩效率。但生产采用不会只看效率:</p><ul><li>编码速度</li><li>解码硬件支持</li><li>浏览器 / 设备兼容</li><li>专利和授权</li><li>转码成本</li></ul><p>H.264 会继续活很久。不是因为它最好,而是因为它最稳。</p><hr><h2 id="二、低延迟会分层" tabindex="-1">二、低延迟会分层 <a class="header-anchor" href="#二、低延迟会分层" aria-label="Permalink to &quot;二、低延迟会分层&quot;">​</a></h2><p>不会所有直播都变 WebRTC。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通观看 -&gt; HLS / DASH / CDN</span></span>
<span class="line"><span>强互动   -&gt; WebRTC</span></span>
<span class="line"><span>专业回传 -&gt; SRT / RIST</span></span>
<span class="line"><span>低延迟大规模 -&gt; LL-HLS / 边缘 WebRTC / 混合架构</span></span></code></pre></div><p>业务要先定延迟目标,再选技术。不要先选协议。</p><hr><h2 id="三、sfu-会更像媒体平台" tabindex="-1">三、SFU 会更像媒体平台 <a class="header-anchor" href="#三、sfu-会更像媒体平台" aria-label="Permalink to &quot;三、SFU 会更像媒体平台&quot;">​</a></h2><p>未来 SFU 不只是转发 RTP:</p><ul><li>录制</li><li>转推</li><li>自动降级</li><li>服务端插帧 / 合流</li><li>AI 字幕</li><li>说话人检测</li><li>质量分析</li><li>边缘调度</li></ul><p>会议系统会越来越像实时媒体平台。</p><hr><h2 id="四、ai-会进入媒体链路" tabindex="-1">四、AI 会进入媒体链路 <a class="header-anchor" href="#四、ai-会进入媒体链路" aria-label="Permalink to &quot;四、AI 会进入媒体链路&quot;">​</a></h2><p>已经很明确的方向:</p><ul><li>实时字幕</li><li>噪声抑制</li><li>回声消除增强</li><li>超分辨率</li><li>背景替换</li><li>内容审核</li><li>智能剪辑</li><li>会议摘要</li></ul><p>注意:AI 能力会吃 GPU / NPU / CPU,还会增加延迟。实时链路里不能无脑加模型。</p><hr><h2 id="五、质量观测会变成标配" tabindex="-1">五、质量观测会变成标配 <a class="header-anchor" href="#五、质量观测会变成标配" aria-label="Permalink to &quot;五、质量观测会变成标配&quot;">​</a></h2><p>未来音视频产品如果没有质量平台,基本不可运维:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户维度: 首帧 / 卡顿 / 丢包 / RTT / 设备</span></span>
<span class="line"><span>房间维度: 上下行码率 / SFU 转发 / 订阅关系</span></span>
<span class="line"><span>区域维度: ISP / CDN / TURN / 边缘节点</span></span>
<span class="line"><span>成本维度: 流量 / 转码 / 存储 / GPU</span></span></code></pre></div><p>音视频不是&quot;出了问题看日志&quot;的系统。日志只是一部分,媒体指标才是主体。</p><hr><h2 id="六、你该掌握什么" tabindex="-1">六、你该掌握什么 <a class="header-anchor" href="#六、你该掌握什么" aria-label="Permalink to &quot;六、你该掌握什么&quot;">​</a></h2><p>读完这个系列,真正要留下的是这些能力:</p><ol><li>看懂容器和编码,知道为什么播不了。</li><li>会用 FFmpeg 做基础处理,知道什么时候不能乱转码。</li><li>理解 HLS / DASH 点播和分片。</li><li>理解 WebRTC 建连链路,知道 STUN / TURN / ICE / SDP / RTP 各自干什么。</li><li>能解释 Mesh / SFU / MCU 的取舍。</li><li>能按指标排查卡顿、黑屏、断音、延迟。</li><li>能算带宽、CDN、存储、转码和 SFU 成本。</li></ol><hr><h2 id="七、下一步项目" tabindex="-1">七、下一步项目 <a class="header-anchor" href="#七、下一步项目" aria-label="Permalink to &quot;七、下一步项目&quot;">​</a></h2><p>最合适的闭环项目:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小型视频会议 + 录制回放系统</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. WebRTC 一对一通话</span></span>
<span class="line"><span>2. TURN 兜底</span></span>
<span class="line"><span>3. 多人 SFU 房间</span></span>
<span class="line"><span>4. 屏幕共享</span></span>
<span class="line"><span>5. 服务端录制</span></span>
<span class="line"><span>6. FFmpeg 转 MP4 / HLS</span></span>
<span class="line"><span>7. 回放播放器</span></span>
<span class="line"><span>8. getStats 质量面板</span></span></code></pre></div><p>这个项目能把本系列 80% 的知识串起来。只看文章不做这个闭环,很容易停在&quot;概念都听过&quot;。</p><hr><h2 id="八、收尾提醒" tabindex="-1">八、收尾提醒 <a class="header-anchor" href="#八、收尾提醒" aria-label="Permalink to &quot;八、收尾提醒&quot;">​</a></h2><ol><li><strong>协议不是目标,体验才是目标</strong>。</li><li><strong>低延迟、高清、低成本不可能同时拉满</strong>。</li><li><strong>先保音频,再保视频</strong>。</li><li><strong>先打指标,再谈优化</strong>。</li><li><strong>先跑通标准链路,再做花活</strong>。</li></ol><p>到这里,音视频工程的主线完成。后面遇到具体问题,回到对应层排查:文件问题看容器/编码/FFmpeg,播放问题看分片/缓冲/播放器,通话问题看 SDP/ICE/RTP/SFU,线上问题看指标和成本。</p>`,41)])])}const g=s(e,[["render",p]]);export{u as __pageData,g as default};
